// rag-demo.ts —— 最小可运行的 Naive RAG（TypeScript）
// 运行：npx tsx rag-demo.ts
// 依赖：npm install openai  （Node >= 16）

import OpenAI from "openai";

const client = new OpenAI(); // 默认读 process.env.OPENAI_API_KEY
const EMBED_MODEL = "text-embedding-3-small";
const CHAT_MODEL = "gpt-4o-mini";

// --- 数据结构：一个最小的内存向量库 ---
interface Chunk {
  id: string;
  text: string;
  vector: number[];
  source: string;
}
const store: Chunk[] = [];

// --- 1. 余弦相似度（OpenAI 向量已归一化，点积即可，这里写完整公式便于理解）---
function cosine(a: number[], b: number[]): number {
  let dot = 0, na = 0, nb = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    na += a[i] * a[i];
    nb += b[i] * b[i];
  }
  return dot / (Math.sqrt(na) * Math.sqrt(nb));
}

// --- 2. 简单分块：按段落 + 长度兜底（生产环境建议用递归/语义分块）---
function chunkText(text: string, maxLen = 500): string[] {
  return text
    .split(/\n\n+/) // 先按空行分段
    .flatMap((p) =>
      p.length > maxLen
        ? p.match(new RegExp(`[\\s\\S]{1,${maxLen}}`, "g")) ?? [p]
        : [p]
    )
    .map((c) => c.trim())
    .filter(Boolean);
}

// --- 3. 入库：文档 -> 分块 -> embedding -> 存储 ---
async function ingest(docText: string, source: string) {
  const chunks = chunkText(docText);
  const res = await client.embeddings.create({
    model: EMBED_MODEL,
    input: chunks, // 批量编码，省请求次数
  });
  chunks.forEach((text, i) => {
    store.push({
      id: `${source}#${i}`,
      text,
      vector: res.data[i].embedding,
      source,
    });
  });
  console.log(`[ingest] ${source}: ${chunks.length} chunks`);
}

// --- 4. 检索：问题 -> embedding -> Top-K ---
async function retrieve(query: string, topK = 3): Promise<Chunk[]> {
  const res = await client.embeddings.create({ model: EMBED_MODEL, input: query });
  const qv = res.data[0].embedding;
  return store
    .map((c) => ({ c, score: cosine(qv, c.vector) }))
    .sort((a, b) => b.score - a.score)
    .slice(0, topK)
    .map((x) => x.c);
}

// --- 5. 生成：拼上下文 + 引用编号 -> LLM ---
async function answer(query: string): Promise<string> {
  const hits = await retrieve(query);
  if (hits.length === 0) return "知识库为空，请先 ingest 文档。";

  const context = hits
    .map((h, i) => `[${i + 1}] (${h.source})\n${h.text}`)
    .join("\n\n");

  const res = await client.chat.completions.create({
    model: CHAT_MODEL,
    messages: [
      {
        role: "system",
        content:
          "你是一个严谨的问答助手。只能基于下面提供的上下文回答问题，" +
          "并在答案中用 [1][2] 标注引用来源。如果上下文里没有答案，请说『知识库中未找到相关内容』，禁止编造。",
      },
      { role: "user", content: `上下文：\n${context}\n\n问题：${query}` },
    ],
  });

  return res.choices[0]?.message?.content ?? "（无响应）";
}

// --- 运行示例 ---
(async () => {
  await ingest(
    "Vue 3 的响应式基于 Proxy 实现。" +
      "相比 Vue 2 的 Object.defineProperty，Proxy 能直接监听对象属性的增删和数组索引修改。\n\n" +
      "ref() 用于基本类型，返回一个带 .value 的对象。" +
      "reactive() 用于对象/数组，返回 Proxy 代理。\n\n" +
      "组合式 API（Composition API）是 Vue 3 的核心特性，通过 setup 函数组织逻辑，便于复用。",
    "vue3-docs.md"
  );

  const q = "Vue 3 怎么监听数组变化？";
  console.log(`\nQ: ${q}`);
  console.log(`A: ${await answer(q)}`);
})();
